CREATE OR REPLACE FUNCTION fpb_get_keep_account_id (as_keep_type_code char ,as_memno char , as_des char , as_loan_type char , as_loan_code char DEFAULT 'X') RETURNS varchar AS $body$
DECLARE

ls_account_id   sc_acc_m_account_master.account_id%type;
ls_account_int  sc_acc_m_account_master.account_id%type;
ls_loan_type    sc_lon_m_rule.loan_type%type;
ls_mem_type     sc_mem_m_ucf_member_type.mem_type_code%type;
li_count            integer;
ls_keep_type_code   sc_kep_m_ucf_keeping_item_type.keeping_type_code%type;

BEGIN

      ls_keep_type_code := as_keep_type_code;

--      if substr( ls_keep_type_code ,1,2) = 'ML'then
-- 
--          begin
--            select count(1) into li_count
--            from sc_lon_m_rule
--            where loan_type = as_loan_type ;
--            exception
--            when no_data_found then li_count := 0 ;
--            when others then spa_dberror('E27 : FPB_GET_KEEP_ACCOUNT_ID');
--          end ;  
--     
--        
--          if li_count = 0 then 
--            ls_keep_type_code := 'xx';
--          end if ;
--      end if;
      case substr( ls_keep_type_code ,1,2)
 
       when 'ML' then   -- เงินกู้
          if as_loan_type = 'SH' then                
              CALL pka_fin.sp_ref_account_share(ls_account_id , pka_mem.fp_get_memType(as_memno) );
          elsif as_loan_type = 'FE' then
           CALL pka_fin.sp_ref_account_mfee(as_memno ,ls_account_id);

          else
              if as_loan_code = '0' then
                  begin  --สัญญาเงินกู้ปกติ
                    select  sc_lon_m_rule.account_id, sc_lon_m_rule.int_account_id
                    into STRICT  ls_account_id,  ls_account_int
                    from  sc_lon_m_rule
                    where ( sc_lon_m_rule.loan_type = as_loan_type );
                  exception when  others then CALL spa_dberror('E41:ไม่พบ sc_lon_m_rule.account_id');end;
              elsif as_loan_code = 'X' then
                  CALL pka_fin.sp_ref_account_loan( trim(both as_des )  ,ls_account_id , ls_account_int);
              else
                  begin --สัญญาเงินกู้ลูกหนี้
                    select  account_id ,  int_account_id
                    into STRICT  ls_account_id,  ls_account_int
                    from sc_lon_m_ucf_loan_code
                    where (loan_code  = as_loan_code);
                  exception when no_data_found then CALL spa_dberror('E50:ไม่พบประเภทลูกหนี้('||trim(both as_loan_code)||')');
                  end;
              end if;
          end if;

        when 'FE' then   -- ค่าธรรมเนียมสมัครสมาชิกใหม่
          CALL pka_fin.sp_ref_account_mfee(as_memno ,ls_account_id);

        when 'MS' then  -- ทุนเรือนหุ้น แยกสามัญ สมทบ
            CALL pka_fin.sp_ref_account_share(ls_account_id , pka_mem.fp_get_memType(as_memno) );

        when 'MD' then  -- เงินฝากรายเดือน
          --Niorn 2022-07-04 TGE ยังไม่ระบุเลขที่บัญชีมา เพราะฝากรายเดือนเปิดบัญชี AUTO 
          CALL pka_fin.sp_ref_account_deposit(trim(both as_des ),ls_account_id);

--          select account_id into ls_account_id
--          from sc_dep_m_rule
--          where deposit_type_code = as_loan_type ;
        when 'FD' then --กองทุน
          ls_loan_type := pka_lon.fp_loantype_conno(trim(both as_des ));
          --ls_account_id := pka_fdm.fp_account_principal(ls_loan_type);
        else  -- บัญชีตามประเภทรายการ
          begin  -- ประเภทการส่งหัก
            select account_id into STRICT ls_account_id
            from sc_kep_m_ucf_keeping_item_type 
            where (keeping_type_code = as_keep_type_code );
            exception when others then CALL spa_dberror('E133:ไม่พบประเภทรายการ('||trim(both as_keep_type_code )||') ในค่าคงที่ระบบ : ทะเบียน ('||as_memno||')');
          end;

        

      end case;

--exception when others then spa_dberror('sssssssss : '|| as_memno);
  RETURN ls_account_id;
--  exception when others then spa_dberror('sssssssss : '|| as_memno);
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
